Voka.scrollWidth=null;Voka.element=[];function Voka(options={}){this.opt=Object.assign({destroyOnClose:true,cssClass:[],footer:false,closeMethod:["button","overlay","esc"]},options);this._template=document.querySelector(this.opt.templateId);if(!this._template){return console.error(`Template "${this.opt.templateId}" not found`)}const{closeMethod:closeMethod}=this.opt;this._allowButtonMethod=closeMethod.includes("button");this._allowEscMethod=closeMethod.includes("esc");this._allowBackdropMethod=closeMethod.includes("overlay");this._footerButtons=[];this._handlerEsc=this._handlerEsc.bind(this)}Voka.prototype.getScrollWidth=function(){if(Voka.scrollWidth)return Voka.scrollWidth;const div=document.createElement("div");Object.assign(div.style,{overflow:"scroll",position:"absolute",top:"-9999px"});document.body.appendChild(div);Voka.scrollWidth=div.offsetWidth-div.clientWidth;document.body.removeChild(div);return Voka.scrollWidth};Voka.prototype.build=function(){const contentElement=this._template.content.cloneNode(true);this._backdrop=document.createElement("div");this._backdrop.className="voka__backdrop";const container=document.createElement("div");container.className="voka__container";if(this.opt.cssClass.length>0){this.opt.cssClass.forEach(cssClass=>{container.classList.add(cssClass)})}if(this._allowButtonMethod){const closeBtn=document.createElement("button");closeBtn.className="voka__close";closeBtn.innerHTML="&times;";container.appendChild(closeBtn);closeBtn.addEventListener("click",()=>{this.close()})}const content=document.createElement("div");content.className="modal-content";content.appendChild(contentElement);container.appendChild(content);if(this.opt.footer){this._footerElement=document.createElement("div");this._footerElement.className="voka__footer";if(this._footerContent){this._footerElement.innerHTML=this._footerContent}if(this._footerButtons.length>0){this._footerButtons.forEach(button=>{this._footerElement.append(button)})}container.appendChild(this._footerElement)}this._backdrop.appendChild(container);if(this._allowBackdropMethod){this._backdrop.addEventListener("click",e=>{if(e.target===this._backdrop){this.close()}})}document.body.appendChild(this._backdrop)};Voka.prototype.setFooterContent=function(html){this._footerContent=html;if(this._footerElement){this._footerElement.innerHTML=this._footerContent}};Voka.prototype.addFooterButton=function(title,cssClass,callback){const button=document.createElement("button");button.innerHTML=title;button.classList.add(cssClass);button.addEventListener("click",callback);this._footerButtons.push(button);if(this._footerElement){this._footerElement.append(button)}};Voka.prototype._toggleBodyScroll=function(isDisable){if(isDisable){const scrollWidth=this.getScrollWidth();const hasScroll=window.innerWidth>document.documentElement.clientWidth;if(hasScroll){document.body.style.paddingRight=`${scrollWidth}px`;document.body.classList.add("voka--no-scroll")}}else if(Voka.element.length===0){document.body.style.paddingRight="";document.body.classList.remove("voka--no-scroll")}};Voka.prototype.open=function(){if(this._backdrop?.classList.contains("voka--show"))return this._backdrop;if(!this._backdrop){this.build()}this._toggleBodyScroll(true);Voka.element.push(this);setTimeout(()=>{this._backdrop.classList.add("voka--show")});if(this._allowEscMethod){document.addEventListener("keydown",this._handlerEsc)}this._onTransitionEnd(()=>{this.opt.onOpen?.()});return this._backdrop};Voka.prototype._handlerEsc=function(e){const lastModal=Voka.element[Voka.element.length-1];if(e.key==="Escape"&&this===lastModal){this.close()}};Voka.prototype._onTransitionEnd=function(callback){this._backdrop.addEventListener("transitionend",callback,{once:true})};Voka.prototype.close=function(destroy=this.opt.destroyOnClose){if(!this._backdrop)return;if(!this._backdrop.classList.contains("voka--show"))return;this._backdrop.classList.remove("voka--show");document.removeEventListener("keydown",this._handlerEsc);this._onTransitionEnd(()=>{Voka.element.pop();if(destroy){this._backdrop.remove();this._backdrop=null}this.opt.onClose?.();this._toggleBodyScroll(false)})};Voka.prototype.destroy=function(){this.close(true)};